void initToDimension()
{
    next initToDimension();

    if(ETGACFParameters::find().EnablefinancialdimensionVertical == NoYes::Yes)
    {
        FormRun            formRun             = this as formRun;
        FormDataSource     formDS              = formRun.dataSource(formDataSourceStr(InventJournalTransfer,InventJournalTrans));
        InventJournalTrans invJournalTrans     = formDS.cursor() as InventJournalTrans;
        InventJournalName  inventJournalName   = InventJournalName::find(invJournalTrans.inventJournalTable().JournalNameId);
        if(inventJournalName && inventJournalName.ETGTransferJournalFDChange == NoYes::Yes)
        {
            tmpDimension.DefaultDimension = inventJournalTrans.ETGToDefaultDimension;
            tmpDimension.insert();
        }
    }
}
